const item = $input.first().json;

// Parse string fields from Supabase first
if (typeof item.step_queue === 'string' && item.step_queue.startsWith('[')) {
  try { item.step_queue = JSON.parse(item.step_queue); } catch(e) {}
}
if (typeof item.completed_steps === 'string') {
  try { item.completed_steps = JSON.parse(item.completed_steps); } catch(e) {}
}

// NOW read state — after parsing so completed_steps is already an array
const current_step    = item._advance?.current_step    ?? item.current_step    ?? 0;
const completed_steps = item._advance?.completed_steps ?? item.completed_steps ?? [];

const isMultiStep = Array.isArray(item.step_queue) && item.step_queue.length > 0;

let resolvedAction, resolvedModule, resolvedRecordId, resolvedFields;

if (isMultiStep) {
  const queue = item.step_queue;
  const step  = queue[current_step];
  if (!step) throw new Error(`Step ${current_step} not found in step_queue (len ${queue.length})`);

  resolvedAction   = step.action;
  resolvedModule   = step.module;
  resolvedRecordId = step.record_id || 'NEW';

  let fields = JSON.parse(JSON.stringify(step.fields || {}));

  function resolveVal(val) {
    if (typeof val === 'string') {
      const m = val.match(/\[\[step_(\d+)_id\]\]/);
      if (m) {
        const resolved = completed_steps[parseInt(m[1]) - 1];
        if (!resolved) throw new Error(`[[step_${m[1]}_id]] not resolved yet`);
        return { id: String(resolved) };
      }
    }
    if (typeof val === 'object' && val !== null && typeof val?.id === 'string') {
      const m = val.id.match(/\[\[step_(\d+)_id\]\]/);
      if (m) {
        const resolved = completed_steps[parseInt(m[1]) - 1];
        if (!resolved) throw new Error(`Nested [[step_${m[1]}_id]] not resolved`);
        return { id: String(resolved) };
      }
    }
    return val;
  }

  for (const key of Object.keys(fields)) fields[key] = resolveVal(fields[key]);
  resolvedFields = fields;

} else {
  resolvedAction   = item.action;
  resolvedModule   = item.module;
  resolvedRecordId = item.record_id;
  resolvedFields   = item.fields || {};
}

return [{ json: {
  ...item,
  current_step,
  completed_steps,
  _resolved: {
    action:           resolvedAction,
    module:           resolvedModule,
    record_id:        resolvedRecordId,
    fields:           resolvedFields,
    is_multi_step:    isMultiStep,
    current_step_idx: current_step,
    total_steps:      isMultiStep ? item.step_queue.length : 1,
  }
}}];

// FORMAT RESULT CODE NODE
// Type: n8n-nodes-base.code
// Position: after Merge (replaces all 11 Edit Fields nodes)

const item = $input.first().json;

// Extract record_id from whichever Zoho response shape was returned
let recordId = null;
if (item.data?.[0]?.details?.id)            recordId = item.data[0].details.id;
else if (item.data?.[0]?.id)               recordId = item.data[0].id;
else if (item.body?.data?.[0]?.details?.id) recordId = item.body.data[0].details.id;
else if (item.record_id && String(item.record_id).match(/^\d{15,20}$/)) recordId = String(item.record_id);
// Never fall back to item.id — that is the Supabase UUID

const action = item._resolved?.action || item.action || 'unknown';

const LABELS = {
  create_deal:'Deal created', update_deal:'Deal updated',
  create_lead:'Lead created', update_lead:'Lead updated', convert_lead:'Lead converted',
  create_contact:'Contact created', update_contact:'Contact updated',
  create_account:'Account created', update_account:'Account updated',
  create_task:'Task created', create_note:'Note added',
};

const label = LABELS[action] || action.replace(/_/g, ' ');

const hasError = (
  item.data?.[0]?.status === 'error' ||
  item.body?.data?.[0]?.status === 'error' ||
  item.status === 'error' ||
  (item.statusCode && item.statusCode >= 400)
);

const errorDetail = hasError
  ? (item.data?.[0]?.message || item.body?.data?.[0]?.message || item.message || 'Unknown error')
  : null;

return [{ json: {
  ...item,
  _result: {
    execution_status: hasError ? 'failed' : 'success',
    action,
    module:      item._resolved?.module || item.module,
    record_id:   recordId,
    user_message: hasError
      ? `Action failed: ${errorDetail}`
      : `${label} successfully${recordId ? ' (ID: ' + recordId + ')' : ''}`,
    error:       errorDetail,
    is_multi_step:    item._resolved?.is_multi_step || false,
    current_step_idx: item._resolved?.current_step_idx || 0,
    total_steps:      item._resolved?.total_steps || 1,
  }
}}];

// STEP ADVANCE CODE NODE
// Type: n8n-nodes-base.code
// Position: after Format Result

const item = $input.first().json;
const result = item._result;

// Parse string fields that may come through as strings from Supabase or Edit Fields
if (typeof item.completed_steps === 'string') {
  try { item.completed_steps = JSON.parse(item.completed_steps); } catch(e) { item.completed_steps = []; }
}
if (typeof item.step_queue === 'string' && item.step_queue.startsWith('[')) {
  try { item.step_queue = JSON.parse(item.step_queue); } catch(e) {}
}

// Detect multi-step directly from step_queue — never trust _result.is_multi_step
// because _resolved gets destroyed by Supabase update nodes before reaching here
const isMultiStep = Array.isArray(item.step_queue) && item.step_queue.length > 1;

const STEP_LABELS = {
  create_deal:'deal', update_deal:'deal update', create_lead:'lead',
  update_lead:'lead update', convert_lead:'lead conversion',
  create_contact:'contact', update_contact:'contact update',
  create_account:'account', update_account:'account update',
  create_task:'task', create_note:'note',
};

if (!isMultiStep) {
  return [{ json: {
    ...item,
    _advance: {
      proposal_id:        item.id,
      user_id:            item.user_id,
      steps_remaining:    0,
      completed_steps:    item.completed_steps || [],
      current_step:       0,
      completion_message: result.user_message,
      execution_result: {
        execution_status: result.execution_status,
        action:           result.action,
        module:           result.module,
        record_id:        result.record_id,
        user_message:     result.user_message,
        error:            result.error || null,
        completed_steps:  [],
      }
    }
  }}];
}

// Multi-step: append record_id, advance pointer
const completedIds  = [...(item.completed_steps || [])];
if (result.record_id) completedIds.push(result.record_id);

const nextStep       = (item.current_step || 0) + 1;
const totalSteps     = item.step_queue.length;
const stepsRemaining = totalSteps - nextStep;

let completionMessage = null;
if (stepsRemaining === 0) {
  const labels = item.step_queue
    .map(s => STEP_LABELS[s.action] || s.action).join(', ');
  completionMessage = `All done! Completed: ${labels}.`;
}

return [{ json: {
  ...item,
  _advance: {
    proposal_id:        item.id,
    user_id:            item.user_id,
    steps_remaining:    stepsRemaining,
    completed_steps:    completedIds,
    current_step:       nextStep,
    completion_message: completionMessage || result.user_message,
    execution_result: {
      execution_status: stepsRemaining === 0 ? result.execution_status : 'in_progress',
      action:           result.action,
      module:           result.module,
      record_id:        result.record_id,
      user_message:     completionMessage || result.user_message,
      error:            result.error || null,
      completed_steps:  completedIds,
    }
  }
}}];

